([0-9]{8})|[0-9]{8})\",\"region\":\"MY\",\"reverse_charge\":true,\"placeholder\":\"A12-3456-78912345\",\"stripe_type\":\"my_sst\",\"supported\":false,\"type\":\"my_sst\",\"country\":\"MY\",\"description\":\"Malaysian SST number\",\"replacement_string\":\"\\\\2-\\\\3-\\\\4\",\"country_label\":\"Malaysia\",\"only_replace_if_group_captured\":2,\"verifiable\":false},\"my_frp\":{\"region\":\"MY\",\"verifiable\":false,\"stripe_type\":\"my_frp\",\"placeholder\":\"12345678\",\"reverse_charge\":true,\"country_label\":\"Malaysia\",\"format\":\"[0-9]{8}\",\"country\":\"MY\",\"supported\":false,\"type\":\"my_frp\",\"description\":\"Malaysian FRP number\"},\"si_vat\":{\"type\":\"si_vat\",\"supported\":true,\"country_label\":\"Slovenia\",\"region\":\"EEA-GB-CH\",\"verifiable\":true,\"stripe_type\":\"eu_vat\",\"description\":\"European VAT number\",\"reverse_charge\":true,\"country\":\"SI\",\"placeholder\":\"SI12345678\",\"format\":\"SI[0-9]{8}\"},\"ca_pst_bc\":{\"type\":\"ca_pst_bc\",\"stripe_type\":\"ca_pst_bc\",\"reverse_charge\":false,\"placeholder\":\"PST-1234-5678\",\"replacement_string\":\"PST-\\\\1-\\\\2\",\"supported\":true,\"region\":\"CA\",\"country_label\":\"Canada\",\"description\":\"Canadian PST number (British Columbia)\",\"country\":\"CA\",\"format\":\"PST-?([0-9]{4})-?([0-9]{4})\",\"verifiable\":false},\"lu_vat\":{\"stripe_type\":\"eu_vat\",\"country\":\"LU\",\"country_label\":\"Luxembourg\",\"type\":\"lu_vat\",\"format\":\"LU[0-9]{8}\",\"region\":\"EEA-GB-CH\",\"placeholder\":\"LU12345678\",\"reverse_charge\":true,\"supported\":true,\"description\":\"European VAT number\",\"verifiable\":true},\"us_ein\":{\"supported\":false,\"type\":\"us_ein\",\"region\":\"US\",\"country_label\":\"United States\",\"placeholder\":\"12-3456789\",\"verifiable\":false,\"replacement_string\":\"\\\\1-\\\\2\",\"country\":\"US\",\"stripe_type\":\"us_ein\",\"description\":\"United States EIN\",\"format\":\"([0-9]{2})-?([0-9]{7})\",\"reverse_charge\":false},\"ru_inn\":{\"country_label\":\"Russia\",\"type\":\"ru_inn\",\"stripe_type\":\"ru_inn\",\"format\":\"[0-9]{10}\",\"verifiable\":false,\"description\":\"Russian INN\",\"region\":\"RU\",\"placeholder\":\"1234567891\",\"reverse_charge\":true,\"country\":\"RU\",\"supported\":true},\"kr_brn\":{\"verifiable\":false,\"format\":\"([0-9]{3})-?([0-9]{2})-?([0-9]{5})\",\"country\":\"KR\",\"region\":\"KR\",\"placeholder\":\"123-45-67890\",\"stripe_type\":\"kr_brn\",\"type\":\"kr_brn\",\"supported\":true,\"country_label\":\"South Korea\",\"reverse_charge\":true,\"description\":\"Korean BRN\",\"replacement_string\":\"\\\\1-\\\\2-\\\\3\"},\"ca_pst_sk\":{\"stripe_type\":\"ca_pst_sk\",\"region\":\"CA\",\"type\":\"ca_pst_sk\",\"country\":\"CA\",\"placeholder\":\"1234567\",\"verifiable\":false,\"reverse_charge\":false,\"supported\":true,\"country_label\":\"Canada\",\"format\":\"([0-9]{7})\",\"description\":\"Canadian PST number (Saskatchewan)\"},\"ca_bn\":{\"verifiable\":false,\"reverse_charge\":false,\"supported\":true,\"placeholder\":\"123456789\",\"country_label\":\"Canada\",\"type\":\"ca_bn\",\"description\":\"Canadian BN\",\"country\":\"CA\",\"region\":\"CA\",\"format\":\"[0-9]{9}\",\"stripe_type\":\"ca_bn\"},\"lt_vat\":{\"region\":\"EEA-GB-CH\",\"country_label\":\"Lithuania\",\"type\":\"lt_vat\",\"stripe_type\":\"eu_vat\",\"supported\":true,\"reverse_charge\":true,\"description\":\"European VAT number\",\"placeholder\":\"LT123456789123\",\"verifiable\":true,\"format\":\"LT([0-9]{9}|[0-9]{12})\",\"country\":\"LT\"}}},\"is_device_based\":false,\"passed\":false},\"4147197039\":{\"name\":\"4147197039\",\"rule_id\":\"3f5MZL85BNc3daNWkQ4sYH:override\",\"secondary_exposures\":[{\"gate\":\"224248639\",\"gateValue\":\"true\",\"ruleID\":\"72U1VSXmKhb3AtsjmM0Tux:100.00:4\"},{\"gate\":\"3602298601\",\"gateValue\":\"true\",\"ruleID\":\"4xVnyyGuW0UVqtMzbMkLpG\"},{\"gate\":\"3643162575\",\"gateValue\":\"true\",\"ruleID\":\"3N3v0gPwp1HzsCs5sPfKke\"},{\"gate\":\"4212341331\",\"gateValue\":\"true\",\"ruleID\":\"7qJW7rFL6bbwTQdSWbaZWg\"}],\"id_type\":\"userID\",\"value\":{\"guess_file_type\":false,\"paste_threshold\":10000},\"is_device_based\":false,\"group_name\":\"10k Threshold\",\"is_experiment_active\":false,\"is_user_in_experiment\":false},\"1977158438\":{\"name\":\"1977158438\",\"rule_id\":\"default\",\"secondary_exposures\":[],\"id_type\":\"userID\",\"value\":{\"user_prompt_key\":\"good_option\",\"enable_web_search\":false,\"system_prompt\":\"The user is asking about an ad shown to them by {advertiser}. Your response must be about the ad shown. They are using the \\\"Ask ChatGPT\\\" feature to get ChatGPT's honest opinion on the product(s) in the advertisement, and in which situations it could be a great fit for them. You should be honest about when you think the product(s) would vs. would not be useful for the user, based on what you know about them.\\n\\nInformation about the ad:\\n{ad}.\\n\\nStructure your response in the following manner:\\n- Briefly describe the type of user, use case, or situation where this ad/product makes sense for the user.\\n- If appropriate, explain any mismatches with the user's stated preferences or goals. That is, where might it fall short for the user (if appropriate)? You don't have to do this for every query, but feel free to list limitations if you think they're pretty relevant.\\n- Give a concise recommendation (e.g., \\\"worth considering,\\\" \\\"probably not ideal,\\\" \\\"good budget option,\\\" \\\"seriously may be a fit,\\\" etc.)\\n\\nGuidelines:\\n- Be honest and practical.\\n- Do not blindly promote the ad.\\n- Avoid harsh or absolute negative language.\\n- Do not invent details not present in the ad.\\n- Focus on fit, not feature lists.\\n- If the mark on relevance is clearly missed, feel free to be funny with it and keep it lighthearted. Do not mock the user or advertiser; keep the humor gentle.\\n\\nKeep it concise, direct, and easy to scan.\\n\\n{conversation}\"},\"is_device_based\":false,\"passed\":false},\"1355628363\":{\"name\":\"1355628363\",\"rule_id\":\"6Ejs5ZDWZjxqVj3jfEBlQn:100.00:4-6Ejs5XYUx1nWBTvnEwFIxl\",\"secondary_exposures\":[],\"id_type\":\"stableID\",\"value\":{\"prompts\":[{\"body\":\"Roleplay a friendly interviewer for a job I’m preparing for. Ask me the role first, then give one question at a time and quick feedback.\",\"title\":\"Practice an interview round\"},{\"body\":\"Help me rewrite a short message in a voice that sounds warm, clear, and like me. Ask me for the draft and the audience.\",\"title\":\"Find my writing voice\"},{\"title\":\"Make a heat day plan\",\"body\":\"Create a text-light heat day plan with icons for shade, water, breaks, cooling, and weather checks. Leave room for my schedule.\"},{\"title\":\"Mix a zero-proof spritz\",\"body\":\"Help me make a zero-proof summer spritz. Ask what fruit or herbs I have, then give a crisp recipe and a batch version.\"},{\"title\":\"Create a time capsule card\",\"body\":\"Create a text-light printable time capsule card for America250 with simple archival icons and blank lines for notes.\"},{\"title\":\"Make a Derby scorecard\",\"body\":\"Make a simple Home Run Derby scorecard I can use with friends. Include casual rules, blank spaces for picks, and a fun scoring twist.\"},{\"title\":\"Build a zero-proof spritz bar\",\"body\":\"Help me set up a zero-proof spritz bar for summer. Give me flavor combos, a shopping list, and a batching plan for guests.\"},{\"body\":\"I'm planning a day at Rocky Mountain National Park this summer. Ask me which date and area, then make an entry plan around the 2026 timed-entry rules.\",\"title\":\"Plan Rocky Mountain entry\"},{\"title\":\"Draw my dinner decision wheel\",\"body\":\"Create an image of a simple dinner decision wheel from ingredients I list or show. I can upload a photo or list them. Keep labels blank.\"},{\"title\":\"Create a baseball bingo card\",\"body\":\"Create a clean, text-light baseball bingo card with 5x5 blank squares and simple field icons. Avoid team logos.\"},{\"title\":\"Practice a hard conversation\",\"body\":\"Help me practice a respectful conversation. Ask what I need to say, then role-play the other person and coach my wording.\"},{\"body\":\"Make a low-key Independence Day mini-adventure for the long weekend. Ask one question about my town or vibe, then suggest a playful plan.\",\"title\":\"Plan a July 4 mini-adventure\"},{\"title\":\"Create backyard game cards\",\"body\":\"Create a text-light set of backyard game cards for July 4, using simple summer icons, blank labels, and no logos.\"},{\"body\":\"Use the latest Wimbledon schedule to suggest a few matches to follow. Ask my time zone if you need it.\",\"title\":\"Pick Wimbledon matches to watch\"},{\"body\":\"Help me turn hot-weather errands into a cooler route with shade breaks, water reminders, and a backup plan. Ask for my city if needed.\",\"title\":\"Plan a cool errand loop\"},{\"body\":\"Help me rehearse a difficult conversation with calm wording and possible replies. Ask me who it’s with and the goal.\",\"title\":\"Rehearse a hard conversation\"},{\"body\":\"Create a text-light Summerween snack table image with pumpkins, popsicles, and spooky-sunny colors. No movie characters or logos.\",\"title\":\"Create a Summerween snack scene\"},{\"body\":\"Create a simple, text-light meal prep visual from what I have. I can upload a fridge photo or list ingredients. Ask for ingredients and timing first.\",\"title\":\"Sketch my meal prep flow\"},{\"body\":\"Help me learn enough about a destination to plan better. Ask where I’m going, then make a short guide to transit basics, food, etiquette, and what to verify.\",\"title\":\"Learn before you travel\"},{\"body\":\"Create a text-light cycling watch board with mountains, sprint, time trial, and rest-day icons. Leave blank spots for stage notes.\",\"title\":\"Map a cycling watch board\"},{\"title\":\"Prep mail before a trip\",\"body\":\"Help me prep my mail before a trip. Ask my travel dates, then compare USPS Hold Mail, Informed Delivery, and package delivery notes.\"},{\"body\":\"Explain a topic I’m curious about using a fresh analogy, a quick example, and one practice question. Ask me the topic.\",\"title\":\"Explain it with an analogy\"},{\"body\":\"Explain hurricane watch, warning, cone, surge, and evacuation zone in plain English. Ask my ZIP code only if local terms matter.\",\"title\":\"Learn hurricane alert terms\"},{\"title\":\"Draw my practice quest\",\"body\":\"Create a text-light visual quest map for a 7-day practice plan. Ask me what skill I’m learning and the final project I want.\"},{\"title\":\"Rewrite an email and learn why\",\"body\":\"I’ll paste an email draft. Rewrite it to be clearer and more useful, then explain three edits I can reuse next time.\"},{\"body\":\"Help me pick summer fruit nail art. Ask my nail length and how bold I want it, then give 5 simple ideas I can show a tech or DIY.\",\"title\":\"Choose fruit nail art\"},{\"title\":\"Build a 5-day learning plan\",\"body\":\"Build me a 5-day summer learning plan around one topic I choose. Ask for the topic first, then make it light and doable.\"},{\"body\":\"Create a text-light frozen yogurt topping map with fruit, crunch, sauce, and savory-sweet sections. Use simple icons and blank labels.\",\"title\":\"Map a froyo topping bar\"},{\"body\":\"Create a simple July Fourth potluck sign-up card with blank spaces for dishes, drinks, setup, and cleanup. Keep it text-light.\",\"title\":\"Make a potluck sign-up card\"},{\"title\":\"Practice for an interview\",\"body\":\"Help me practice for an interview. Ask what role I’m targeting, then run one question at a time and coach my answer structure.\"},{\"body\":\"Create a simple, text-light hurricane kit label sheet with icons for water, food, meds, flashlights, documents, pets, and blank spaces.\",\"title\":\"Make a storm kit label\"},{\"title\":\"Create produce storage labels\",\"body\":\"Create a text-light produce storage label sheet for a summer market haul, with blank labels and simple icons for counter, fridge, and use soon.\"},{\"body\":\"Create a text-light visual concept for refreshing one room with items I already own. I can upload a photo or describe the space.\",\"title\":\"Show a room refresh concept\"},{\"title\":\"Polish a tricky email\",\"body\":\"Help me rewrite a message so it sounds clear and respectful. Ask me to paste the draft and name the outcome I want.\"},{\"title\":\"Build a summer reading quest\",\"body\":\"Make me a two-week summer reading quest inspired by Unearth a Story, with prompts for books, local history, and one tiny artifact.\"},{\"body\":\"Create a text-light summer reading bingo card with beach icons, blank squares, and space to add my own book titles.\",\"title\":\"Create a book bingo card\"},{\"title\":\"Turn a walk into a field trip\",\"body\":\"Turn an ordinary walk near me into a mini field trip with things to notice and a reflection prompt. Ask me for the neighborhood or park.\"},{\"title\":\"Make my resume bullet stronger\",\"body\":\"Turn one resume bullet into a stronger achievement statement. Ask me for the bullet and the result or metric if I have one.\"},{\"body\":\"Teach me 12 soccer terms I’ll hear during the World Cup, with one plain-English example for each.\",\"title\":\"Speak soccer for the Cup\"},{\"title\":\"Plan a July 4 cookout\",\"body\":\"Help me plan a July 4 cookout menu and timeline. Ask one question about guests or dietary needs before you tailor it.\"},{\"body\":\"Help me turn a vague meeting goal into a useful agenda. Ask the goal, then draft talking points and explain why each part matters.\",\"title\":\"Turn a goal into an agenda\"},{\"title\":\"Plan groceries with less waste\",\"body\":\"Help me plan groceries for the week so fewer items go unused. Ask how many dinners I need and what I already have.\"},{\"body\":\"Build a playful watch-party game for a 2026 World Cup match. Ask which teams I’m watching, then give easy rules and a few goofy bonus points.\",\"title\":\"Make a World Cup watch game\"},{\"title\":\"Create a soccer bingo card\",\"body\":\"Create a text-light soccer bingo card for a 2026 World Cup watch party, with simple icons, blank squares, and no team logos.\"},{\"title\":\"Style a soccer-watch outfit\",\"body\":\"Help me make a soccer-watch outfit from what I own. I can upload a closet photo or describe pieces. Keep it logo-free and comfortable.\"},{\"body\":\"Give me a playful Spam hot dog remix with one classic, one spicy, and one surprise topping combo.\",\"title\":\"Remix hot dog night\"},{\"body\":\"Create a text-light soccer watch poster with blank team spaces, kickoff icons, snack doodles, no logos, and a fun living-room vibe.\",\"title\":\"Make a soccer watch poster\"},{\"title\":\"Shop the tax-free maze\",\"body\":\"Ask what state I’m shopping in, then check current back-to-school tax holiday dates and turn my supply list into a store quest.\"},{\"title\":\"Make a blank soccer bracket\",\"body\":\"Create a text-light blank soccer knockout bracket I can fill in during the 2026 World Cup, using simple field lines and no logos.\"},{\"title\":\"Make a road-trip snack map\",\"body\":\"Plan road-trip snacks around real stops. Ask my route first, then make a cooler-friendly snack plan and a safe-break rhythm.\"},{\"body\":\"Create a text-light nail inspo sheet with 5 fruit-color swatches, simple icons, blank labels, and no hands or brand logos.\",\"title\":\"Make a nail inspo sheet\"},{\"title\":\"Join the couch peloton\",\"body\":\"Turn a Tour de France stage into a couch-peloton game with team names, snack-zone rules, and a tiny glossary for a new fan.\"},{\"title\":\"Tame one messy spot\",\"body\":\"Help me turn one messy spot into a 20-minute cleanup game. I can upload a photo or describe the area.\"},{\"title\":\"Turn studying into a quest\",\"body\":\"Turn something I need to learn into a 25-minute quest with checkpoints, a tiny reward, and one self-quiz. Ask me the topic first.\"},{\"body\":\"Create an image of a text-light pantry meal formula card with simple food icons and blank labels for protein, vegetable, starch, and sauce.\",\"title\":\"Create a pantry formula card\"},{\"title\":\"Understand mail forwarding\",\"body\":\"Teach me the difference between USPS change of address, mail forwarding, and hold mail. Ask whether I’m moving or traveling first.\"},{\"title\":\"Make an everyday decision\",\"body\":\"Help me choose between everyday options by turning them into safe, bold, and balanced scenarios. Ask me what I’m deciding.\"},{\"title\":\"Turn notes into a study plan\",\"body\":\"I’ll paste messy notes. Turn them into a study plan with key ideas, gaps to clarify, and a short practice exercise.\"},{\"body\":\"Help me pick five Tour de France stages to watch this year and explain the drama of each in plain English.\",\"title\":\"Pick Tour de France stages\"},{\"body\":\"Help me decide whether US Open Fan Week is worth a visit, with what is free, what needs a pass, and what to check before going.\",\"title\":\"Plan a US Open Fan Week visit\"},{\"title\":\"Check school tax holiday rules\",\"body\":\"Ask my state first, then check whether there's a back-to-school sales tax holiday and make a school-supply shopping plan.\"},{\"body\":\"Give me a playful guide to the next World Cup match, with the stakes, one player to watch, and a silly chant idea. Ask who I’m rooting for.\",\"title\":\"Catch the World Cup vibe\"},{\"body\":\"Create a cheerful, text-light ice cream menu board for National Ice Cream Day with blank flavor spaces and simple topping icons.\",\"title\":\"Create an ice cream menu\"},{\"body\":\"Upload a package photo or name the item and my city. Help me figure out trash, recycling, compost, or drop-off without guesswork.\",\"title\":\"Decode the bin mystery\"},{\"title\":\"Create fruit nail inspo\",\"body\":\"Create a text-light image of simple fruit nail ideas with blueberry, watermelon, cherry, lemon, and peach motifs. No brand logos.\"},{\"body\":\"Help me price a garage-sale table like a game, with fair bundles, simple signs, and polite haggling lines.\",\"title\":\"Price a garage-sale table\"},{\"body\":\"Create a simple image of a hurricane kit shelf with blank zones for water, lights, batteries, chargers, first aid, and documents.\",\"title\":\"Create a storm-kit shelf guide\"},{\"body\":\"Help me make a small America250 time capsule: 10 items, one letter prompt, and a way to revisit it later.\",\"title\":\"Make a 250-year time capsule\"},{\"title\":\"Pick a fruit nail vibe\",\"body\":\"Help me choose a summer fruit nail vibe. Compare blueberry, watermelon, cherry, lemon, and peach in a playful way.\"},{\"title\":\"Plan a July Fourth cookout\",\"body\":\"Make a July Fourth cookout timeline with food safety checkpoints and a simple prep order. Ask how many people before sizing the food.\"},{\"title\":\"Draft a reply that sounds like me\",\"body\":\"Help me reply to a message with warmth and a little wit. I’ll paste the message, and you can ask what tone I want if it’s unclear.\"},{\"body\":\"Make a baseball bingo card for MLB All-Star Week with plays, broadcast moments, and funny but friendly squares.\",\"title\":\"Make All-Star Game bingo\"},{\"body\":\"Help me turn a public library summer reading program into a simple reading plan. Ask my library system or city first.\",\"title\":\"Find a summer reading path\"},{\"body\":\"Create a text-light packing visual for my trip. Ask for the destination and trip length first, then make it easy to scan.\",\"title\":\"Make a packing visual\"},{\"title\":\"Turn notes into a meeting recap\",\"body\":\"Turn my rough meeting notes into a concise recap with decisions, owners, and next steps. Ask me to paste the notes first.\"},{\"body\":\"I’ll paste a recipe step. Teach me the technique behind it, what to watch for, and how to tell when it’s done.\",\"title\":\"Understand a recipe step\"},{\"title\":\"Understand the World Cup bracket\",\"body\":\"Use the latest 2026 World Cup bracket to teach me how the knockout rounds work and what to watch for in the next match.\"},{\"title\":\"Decode an electric bill\",\"body\":\"Explain kWh, rate, fees, and smart meter in a US electric bill. If I paste line items, translate them into plain English.\"},{\"body\":\"Help me choose a vacation read by asking one question, then give me 5 playful picks by mood with a beach-bag rating.\",\"title\":\"Pick a vacation read\"},{\"body\":\"Plan a low-key Wimbledon breakfast watch: easy menu, scoring cheat sheet, and a friendly intro for someone new to tennis.\",\"title\":\"Host a Wimbledon breakfast\"},{\"body\":\"Make a spoiler-light catch-up plan before Spider-Man: Brand New Day. Include only the movies or scenes that matter most.\",\"title\":\"Catch up before Spider-Man\"},{\"body\":\"I can upload a crochet inspiration photo or describe what I want to make. Help me pick yarn, estimate time, and plan first steps.\",\"title\":\"Pick a crochet summer project\"},{\"title\":\"Turn notes into next moves\",\"body\":\"Turn my rough meeting notes into a crisp recap with action items, owners, and a tiny wins section. If owners are missing, mark them TBD.\"},{\"body\":\"Create a text-light printable World Cup match tracker with blank team lines, score boxes, and simple soccer icons. No logos.\",\"title\":\"Print a match tracker\"},{\"title\":\"Turn my market haul into meals\",\"body\":\"Create a simple illustrated meal board from my farmers market haul. I'll upload a photo or list what I bought. Keep labels minimal.\"},{\"body\":\"Create a text-light fireworks safety layout with simple icons for water, viewing area, and no-go space. Do not include brand logos.\",\"title\":\"Make a fireworks safety map\"},{\"body\":\"Help me plan errands for a hot day. Ask for my ZIP code and must-do stops, then suggest a safer schedule and what to bring.\",\"title\":\"Plan errands around heat\"},{\"title\":\"Restart summer reading\",\"body\":\"Help me restart summer reading with my 